commonMistakes.wrongCode:
@keyframes slideIn {
  from { transform: translateX(-100%); }
  to   { transform: translateX(0); }
}
.card {
  animation: slideIn 1s;
}
/* After animation, card snaps back to its original style — translateX(-100%) if set, or default */

commonMistakes.correctCode:
.card {
  animation: slideIn 1s forwards;
  /* or: animation-fill-mode: forwards; */
}

commonMistakes.wrongCode:
@keyframes moveRight {
  from { left: 0; }
  to   { left: 200px; }
}
.box {
  position: absolute;
  animation: moveRight 1s infinite;
}
/* Jerky on lower-end devices */

commonMistakes.correctCode:
@keyframes moveRight {
  from { transform: translateX(0); }
  to   { transform: translateX(200px); }
}

commonMistakes.wrongCode:
.spinner {
  animation: spin 1s infinite;
}
/* No @keyframes spin defined anywhere */

commonMistakes.correctCode:
@keyframes spin {
  from { transform: rotate(0deg); }
  to   { transform: rotate(360deg); }
}

.spinner {
  animation: spin 1s linear infinite;
}

commonMistakes.wrongCode:
@keyframes buttonHover {
  from { background: red; }
  to   { background: blue; }
}
.btn:hover {
  animation: buttonHover 0.3s forwards;
}
/* Overkill! */

commonMistakes.correctCode:
.btn {
  background: red;
  transition: background 0.3s;
}
.btn:hover {
  background: blue;
}

